12	
13	# TagsInput
14	
15	A text input that converts entries into removable tags/chips. Supports add, edit, remove,
16	paste, and navigation between tags.
17	
18	## 1. State Machine
19	
20	### 1.1 States
21	
22	```rust
23	/// The states of the TagsInput state machine.
24	#[derive(Clone, Copy, Debug, PartialEq)]
25	pub enum State {
26	    /// The component is in an idle state.
27	    Idle,
28	    /// The component is in a focused state.
29	    Focused,
30	    /// The component is in an editing tag state.
31	    EditingTag {
32	        /// The index of the tag being edited.
33	        index: usize,
34	    },
35	}
36	```
37	
38	### 1.2 Events
39	
40	```rust
41	/// The events of the TagsInput state machine.
42	#[derive(Clone, Debug, PartialEq)]
43	pub enum Event {
44	    /// Add a new tag.
45	    AddTag(String),
46	    /// Remove a tag by value.
47	    RemoveTag(String),
48	    /// Remove a tag by index.
49	    RemoveTagAtIndex(usize),
50	    /// Enter edit mode for a tag.
51	    EditTag {
52	        /// The index of the tag being edited.
53	        index: usize,
54	    },
55	    /// Commit an edit.
56	    CommitEdit {
57	        /// The index of the tag being edited.
58	        index: usize,
59	        /// The new value of the tag.
60	        value: String,
61	    },
62	    /// Cancel edit mode.
63	    CancelEdit,
64	    /// Focus received.
65	    Focus {
66	        /// True if the focus was initiated by a keyboard.
67	        is_keyboard: bool,
68	    },
69	    /// Focus lost.
70	    Blur,
71	    /// Input text changed.
72	    InputChange(String),
73	    /// Text pasted — may contain delimiters.
74	    Paste(String),
75	    /// Clear all tags.
76	    ClearAll,
77	    /// Navigate to previous tag.
78	    FocusPrevTag,
79	    /// Navigate to next tag (or back to input).
80	    FocusNextTag,
81	    /// IME composition started (CJK, etc.).
82	    CompositionStart,
83	    /// IME composition ended.
84	    CompositionEnd,
85	}
86	```
87	
88	> **IME composition:** This component tracks `is_composing: bool` in `Context`. During composition (`is_composing == true`), Enter key MUST NOT trigger `AddTag` and delimiter detection MUST be suppressed. See §IME in `03-accessibility.md`.
89	> See also [IME Composition Handling](10-input-components.md#ime-composition-protocol) for the shared input method editor behavior during text composition.
90	
91	### 1.3 Context
92	
93	```rust
94	/// The context for the TagsInput state machine.
95	#[derive(Clone, Debug, PartialEq)]
96	pub struct Context {
97	    /// TagsInput uses Vec for insertion-order preservation. Duplicate prevention is enforced in transition logic.
98	    pub value: Bindable<Vec<String>>,
99	    /// The current input value.
100	    pub input_value: String,
101	    /// Whether the component is focused.
102	    pub focused: bool,
103	    /// Whether the focus is visible.
104	    pub focus_visible: bool,
105	    /// The index of the focused tag.
106	    pub focused_tag: Option<usize>,
107	    /// The index of the tag being edited.
108	    pub editing_tag: Option<usize>,
109	    /// Whether the component is disabled.
110	    pub disabled: bool,
111	    /// Whether the component is readonly.
112	    pub readonly: bool,
113	    /// Whether the component is invalid.
114	    pub invalid: bool,
115	    /// The maximum number of tags.
116	    pub max: Option<usize>,
117	    /// The delimiter for the tags.
118	    pub delimiter: String,
119	    /// Whether to add a tag on paste.
120	    pub add_on_paste: bool,
121	    /// Whether to allow duplicates.
122	    pub allow_duplicates: bool,
123	    /// What happens to pending input on blur.
124	    pub blur_behavior: BlurBehavior,
125	    /// True while an IME composition session is active (between CompositionStart and CompositionEnd).
126	    pub is_composing: bool,
127	    /// The name of the component.
128	    pub name: Option<String>,
129	    /// Resolved locale for i18n.
130	    pub locale: Locale,
131	    /// Component IDs for part identification.
132	    pub ids: ComponentIds,
133	    /// Resolved messages for accessibility labels.
134	    pub messages: Messages,
135	}
136	```
137	
138	### 1.4 Props
139	
140	```rust
141	/// The props for the TagsInput component.
142	#[derive(Clone, Debug, PartialEq, HasId)]
143	pub struct Props {
144	    /// The id of the component.
145	    pub id: String,
146	    /// The value of the component.
147	    pub value: Option<Vec<String>>,
148	    /// The default value of the component.
149	    pub default_value: Vec<String>,
150	    /// The maximum number of tags.
151	    pub max: Option<usize>,
152	    /// Whether the component is disabled.
153	    pub disabled: bool,
154	    /// Whether the component is readonly.
155	    pub readonly: bool,
156	    /// Whether the component is invalid.
157	    pub invalid: bool,
158	    /// The delimiter for the tags.
159	    pub delimiter: String,
160	    /// Whether to add a tag on paste.
161	    pub add_on_paste: bool,
162	    /// Whether to allow duplicates.
163	    pub allow_duplicates: bool,
164	    /// Whether the tags input is required.
165	    pub required: bool,
166	    /// Maximum character length per tag.
167	    pub max_length: Option<usize>,
168	    /// The name of the component.
169	    pub name: Option<String>,
170	    /// The placeholder for the input.
171	    pub placeholder: Option<String>,
172	    /// When `true`, tags can be edited inline by pressing Enter on a focused tag or
173	    /// double-clicking a tag. The tag enters an inline edit mode where the user can
174	    /// modify the text. Pressing Enter commits the edit; Escape cancels it.
175	    /// Default: `false`.
176	    pub editable: bool,
177	    /// What happens to pending input text when the component loses focus.
178	    /// `Add` creates a tag from the current input (if non-empty and valid).
179	    /// `Clear` discards the pending input. Default: `BlurBehavior::Add`.
180	    pub blur_behavior: BlurBehavior,
181	    // Change callbacks provided by the adapter layer
182	}
183	
184	/// What happens to pending input when TagsInput loses focus.
185	#[derive(Clone, Copy, Debug, PartialEq, Default)]
186	pub enum BlurBehavior {
187	    /// Create a tag from the current input text (if non-empty and valid).
188	    #[default]
189	    Add,
190	    /// Discard the pending input text.
191	    Clear,
192	}
193	
194	impl Default for Props {
195	    fn default() -> Self {
196	        Self {
197	            id: String::new(),
198	            value: None, default_value: Vec::new(),
199	            max: None, disabled: false, readonly: false, invalid: false,
200	            delimiter: ",".into(), add_on_paste: true, allow_duplicates: false,
201	            required: false, max_length: None,
202	            name: None, placeholder: None,
203	            editable: false,
204	            blur_behavior: BlurBehavior::Add,
205	        }
206	    }
207	}
208	```
209	
210	### 1.5 TagsInput Inline Editing
211	
212	When `editable: true`, tags support inline editing via the following state/event additions:
213	
214	**Additional State**: The `EditingTag { index: usize }` state (already defined in the State enum)
215	becomes reachable. During this state, the tag at `index` renders an inline text input
216	pre-filled with the tag's current value.
217	
218	**Editing Context Fields**:
219	
220	```rust,no_check
221	// Already present in Context:
222	pub editing_tag: Option<usize>,     // Index of the tag currently being edited
223	
224	// Additional editing context (added to Context):
225	/// Draft text for the tag currently being edited. Initialized from the tag's
226	/// current value when editing starts; updated on each keystroke during edit.
227	pub editing_draft: String,
228	```
229	
230	**Editing Events**: The following events (already defined in the Event enum) drive the editing flow:
231	
232	| Event                         | Trigger                                                         | Behavior                                                                                                                                                                                     |
233	| ----------------------------- | --------------------------------------------------------------- | -------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------- |
234	| `EditTag { index }`           | Enter key on focused tag, or double-click when `editable: true` | Transition to `EditingTag { index }`. Set `editing_tag = Some(index)`, `editing_draft` = current tag value. Focus the inline input.                                                          |
235	| `CommitEdit { index, value }` | Enter key during edit                                           | If `value` is non-empty and passes duplicate validation (when `allow_duplicates: false`), replace the tag at `index`. Transition back to `Focused`. Clear `editing_tag` and `editing_draft`. |
236	| `CancelEdit`                  | Escape key during edit                                          | Discard `editing_draft`. Transition back to `Focused`. Return focus to the tag at the editing index.                                                                                         |
237	| `InputChange(text)`           | Typing in the inline edit input                                 | Update `editing_draft` with the new text. No state transition.                                                                                                                               |
238	
239	**Keyboard Bindings During Editing**:
240	
241	| Key    | In `Focused` state (tag focused)                     | In `EditingTag` state        |
242	| ------ | ---------------------------------------------------- | ---------------------------- |
243	| Enter  | Start edit (`EditTag { index }`) if `editable: true` | Commit edit (`CommitEdit`)   |
244	| Escape | —                                                    | Cancel edit (`CancelEdit`)   |
245	| Tab    | Move focus to next tag or input                      | Commit edit, then move focus |
246	
247	**Guard**: `EditTag`, `CommitEdit`, and `CancelEdit` events are rejected when `editable: false`,
248	`disabled: true`, or `readonly: true`.
249	
250	### 1.6 Full Machine Implementation
251	
252	```rust
253	/// The machine for the TagsInput component.
254	pub struct Machine;
255	
256	impl ars_core::Machine for Machine {
257	    type State = State;
258	    type Event = Event;
259	    type Context = Context;
260	    type Props = Props;
261	    type Api<'a> = Api<'a>;
262	    type Messages = Messages;
263	
264	    fn init(props: &Self::Props, env: &Env, messages: &Self::Messages) -> (Self::State, Self::Context) {
265	        let state = State::Idle;
266	        let locale = env.locale.clone();
267	        let messages = messages.clone();
268	        let ctx = Context {
269	            value: match &props.value {
270	                Some(v) => Bindable::controlled(v.clone()),
271	                None => Bindable::uncontrolled(props.default_value.clone()),
272	            },
273	            input_value: String::new(),
274	            focused: false,
275	            focus_visible: false,
276	            focused_tag: None,
277	            editing_tag: None,
278	            disabled: props.disabled,
279	            readonly: props.readonly,
280	            invalid: props.invalid,
281	            max: props.max,
282	            delimiter: props.delimiter.clone(),
283	            add_on_paste: props.add_on_paste,
284	            allow_duplicates: props.allow_duplicates,
285	            blur_behavior: props.blur_behavior,
286	            is_composing: false,
287	            name: props.name.clone(),
288	            locale,
289	            ids: ComponentIds::from_id(&props.id),
290	            messages,
291	        };
292	
293	        (state, ctx)
294	    }
295	
296	    fn transition(
297	        state: &Self::State,
298	        event: &Self::Event,
299	        ctx: &Self::Context,
300	        props: &Self::Props,
301	    ) -> Option<TransitionPlan<Self>> {
302	        if ctx.disabled || ctx.readonly {
303	            match event {
304	                Event::AddTag(_)
305	                | Event::RemoveTag(_)
306	                | Event::RemoveTagAtIndex(_)
307	                | Event::EditTag { .. }
308	                | Event::CommitEdit { .. }
309	                | Event::ClearAll
310	                | Event::Paste(_) => return None,
311	                _ => {}
312	            }
313	        }
314	
315	        match event {
316	            Event::AddTag(tag) => {
317	                let tag = tag.trim().to_string();
318	                if tag.is_empty() { return None; }
319	
320	                // Check max
321	                if let Some(max) = ctx.max {
322	                    if ctx.value.get().len() >= max { return None; }
323	                }
324	
325	                // Check duplicates
326	                if !ctx.allow_duplicates && ctx.value.get().contains(&tag) {
327	                    return None;
328	                }
329	
330	                let allow_dupes = ctx.allow_duplicates;
331	                Some(TransitionPlan::context_only(move |ctx| {
332	                    let mut tags = ctx.value.get().clone();
333	                    if allow_dupes || !tags.contains(&tag) {
334	                        tags.push(tag);
335	                    }
336	                    ctx.value.set(tags);
337	                    ctx.input_value.clear();
338	                }))
339	            }
340	
341	            Event::RemoveTag(val) => {
342	                let val = val.clone();
343	                Some(TransitionPlan::context_only(move |ctx| {
344	                    let mut tags = ctx.value.get().clone();
345	                    let removed_idx = tags.iter().position(|t| t == &val);
346	                    tags.retain(|t| t != &val);
347	                    ctx.value.set(tags.clone());
348	                    if tags.is_empty() {
349	                        ctx.focused_tag = None;
350	                    } else if let Some(idx) = removed_idx {
351	                        ctx.focused_tag = Some(idx.min(tags.len() - 1));
352	                    }
353	                }).with_effect(PendingEffect::new("focus_tag", |ctx, _props, _send| {
354	                    if let Some(idx) = ctx.focused_tag {
355	                        let platform = use_platform_effects();
356	                        let tag_id = ctx.ids.item("tag", &idx);
357	                        platform.focus_element_by_id(&tag_id);
358	                    }
359	                    no_cleanup()
360	                })))
361	            }
362	
363	            Event::RemoveTagAtIndex(idx) => {
364	                let idx = *idx;
365	                if idx >= ctx.value.get().len() { return None; }
366	                Some(TransitionPlan::context_only(move |ctx| {
367	                    let mut tags = ctx.value.get().clone();
368	                    if idx < tags.len() {
369	                        tags.remove(idx);
370	                        ctx.value.set(tags.clone());
371	                        if tags.is_empty() {
372	                            ctx.focused_tag = None;
373	                        } else {
374	                            ctx.focused_tag = Some(idx.min(tags.len() - 1));
375	                        }
376	                    }
377	                }).with_effect(PendingEffect::new("focus_tag", |ctx, _props, _send| {
378	                    if let Some(idx) = ctx.focused_tag {
379	                        let platform = use_platform_effects();
380	                        let tag_id = ctx.ids.item("tag", &idx);
381	                        platform.focus_element_by_id(&tag_id);
382	                    }
383	                    no_cleanup()
384	                })))
385	            }
386	
387	            Event::EditTag { index } => {
388	                if *index >= ctx.value.get().len() { return None; }
389	                let idx = *index;
390	                Some(TransitionPlan::to(State::EditingTag { index: idx }).apply(move |ctx| {
391	                    ctx.editing_tag = Some(idx);
392	                }).with_effect(PendingEffect::new("focus_edit_input", |ctx, _props, _send| {
393	                    if let Some(idx) = ctx.editing_tag {
394	                        let platform = use_platform_effects();
395	                        let edit_id = ctx.ids.item("tag-edit-input", &idx);
396	                        platform.focus_element_by_id(&edit_id);
397	                    }
398	                    no_cleanup()
399	                })))
400	            }
401	
402	            Event::CommitEdit { index, value } => {
403	                let idx = *index;
404	                let val = value.trim().to_string();
405	                Some(TransitionPlan::to(State::Focused).apply(move |ctx| {
406	                    if val.is_empty() {
407	                        let mut tags = ctx.value.get().clone();
408	                        if idx < tags.len() {
409	                            tags.remove(idx);
410	                            ctx.value.set(tags);
411	                        }
412	                    } else {
413	                        let mut tags = ctx.value.get().clone();
414	                        if idx < tags.len() {
415	                            tags[idx] = val;
416	                            ctx.value.set(tags);
417	                        }
418	                    }
419	                    ctx.editing_tag = None;
420	                }).with_effect(PendingEffect::new("focus_input", |ctx, _props, _send| {
421	                    let platform = use_platform_effects();
422	                    let input_id = ctx.ids.part("input");
423	                    platform.focus_element_by_id(&input_id);
424	                    no_cleanup()
425	                })))
426	            }
427	
428	            Event::CancelEdit => {
429	                Some(TransitionPlan::to(State::Focused).apply(|ctx| {
430	                    ctx.editing_tag = None;
431	                }).with_effect(PendingEffect::new("focus_input", |ctx, _props, _send| {
432	                    let platform = use_platform_effects();
433	                    let input_id = ctx.ids.part("input");
434	                    platform.focus_element_by_id(&input_id);
435	                    no_cleanup()
436	                })))
437	            }
438	
439	            Event::Focus { is_keyboard } => {
440	                let is_kb = *is_keyboard;
441	                Some(TransitionPlan::to(State::Focused).apply(move |ctx| {
442	                    ctx.focused = true;
443	                    ctx.focus_visible = is_kb;
444	                    ctx.focused_tag = None;
445	                }))
446	            }
447	
448	            Event::Blur if matches!(state, State::EditingTag { .. }) => {
449	                let idx = match state {
450	                    State::EditingTag { index } => *index,
451	                    _ => 0,
452	                };
453	                Some(TransitionPlan::to(State::Idle).apply(move |ctx| {
454	                    // Commit the in-progress edit before transitioning
455	                    ctx.editing_tag = None;
456	                    ctx.focused = false;
457	                    ctx.focus_visible = false;
458	                    ctx.focused_tag = None;
459	                }))
460	            }
461	
462	            Event::Blur => {
463	                // Respect blur_behavior: Add creates a tag, Clear discards input.
464	                let input_trimmed = ctx.input_value.trim().to_string();
465	                let should_attempt_add = ctx.blur_behavior == BlurBehavior::Add;
466	                let can_add = should_attempt_add
467	                    && !input_trimmed.is_empty()
468	                    && ctx.max.map_or(true, |m| ctx.value.get().len() < m)
469	                    && (ctx.allow_duplicates || !ctx.value.get().contains(&input_trimmed));
470	                let tag_to_add = if can_add { Some(input_trimmed) } else { None };
471	
472	                Some(TransitionPlan::to(State::Idle).apply(move |ctx| {
473	                    if let Some(tag) = tag_to_add {
474	                        let mut tags = ctx.value.get().clone();
475	                        tags.push(tag);
476	                        ctx.value.set(tags);
477	                    }
478	                    ctx.input_value.clear();
479	                    ctx.focused = false;
480	                    ctx.focus_visible = false;
481	                    ctx.focused_tag = None;
482	                }))
483	            }
484	
485	            Event::InputChange(val) => {
486	                let val = val.clone();
487	                Some(TransitionPlan::context_only(move |ctx| {
488	                    ctx.input_value = val;
489	                    ctx.focused_tag = None;
490	                }))
491	            }
492	
493	            Event::Paste(text) => {
494	                if !ctx.add_on_paste {
495	                    let text = text.clone();
496	                    return Some(TransitionPlan::context_only(move |ctx| {
497	                        ctx.input_value = text;
498	                    }));
499	                }
500	                let delimiter = ctx.delimiter.clone();
501	                let max = ctx.max;
502	                let allow_duplicates = ctx.allow_duplicates;
503	                let parts: Vec<String> = text.split(&delimiter)
504	                    .map(|s| s.trim().to_string())
505	                    .filter(|s| !s.is_empty())
506	                    .collect();
507	                let current_tags = ctx.value.get().clone();
508	                Some(TransitionPlan::context_only(move |ctx| {
509	                    let mut tags = current_tags;
510	                    for part in parts {
511	                        if max.map_or(true, |m| tags.len() < m)
512	                            && (allow_duplicates || !tags.contains(&part))
513	                        {
514	                            tags.push(part);
515	                        }
516	                    }
517	                    ctx.value.set(tags);
518	                    ctx.input_value.clear();
519	                }))
520	            }
521	
522	            Event::ClearAll => {
523	                Some(TransitionPlan::context_only(|ctx| {
524	                    ctx.value.set(Vec::new());
525	                    ctx.input_value.clear();
526	                }))
527	            }
528	
529	            Event::FocusPrevTag => {
530	                let len = ctx.value.get().len();
531	                if len == 0 { return None; }
532	                let current_tag = ctx.focused_tag;
533	                let new_idx = match current_tag {
534	                    Some(idx) if idx > 0 => idx - 1,
535	                    Some(0) => 0,
536	                    None => len - 1,
537	                    _ => 0,
538	                };
539	                Some(TransitionPlan::context_only(move |ctx| {
540	                    ctx.focused_tag = Some(new_idx);
541	                }).with_effect(PendingEffect::new("focus_tag", |ctx, _props, _send| {
542	
543	                    if let Some(idx) = ctx.focused_tag {
544	                        let platform = use_platform_effects();
545	                        let tag_id = ctx.ids.item("tag", &idx);
546	                        platform.focus_element_by_id(&tag_id);
547	                    }
548	                    no_cleanup()
549	                })))
550	            }
551	
552	            Event::FocusNextTag => {
553	                let len = ctx.value.get().len();
554	                let current_tag = ctx.focused_tag;
555	                match current_tag {
556	                    Some(idx) if idx + 1 < len => {
557	                        let next = idx + 1;
558	                        Some(TransitionPlan::context_only(move |ctx| {
559	                            ctx.focused_tag = Some(next);
560	                        }).with_effect(PendingEffect::new("focus_tag", |ctx, _props, _send| {
561	                            if let Some(idx) = ctx.focused_tag {
562	                                let platform = use_platform_effects();
563	                                let tag_id = ctx.ids.item("tag", &idx);
564	                                platform.focus_element_by_id(&tag_id);
565	                            }
566	                            no_cleanup()
567	                        })))
568	                    }
569	                    Some(_) => {
570	                        // Past last tag → focus input
571	                        Some(TransitionPlan::context_only(|ctx| {
572	                            ctx.focused_tag = None;
573	                        }).with_effect(PendingEffect::new("focus_input", |ctx, _props, _send| {
574	                            let platform = use_platform_effects();
575	                            let input_id = ctx.ids.part("input");
576	                            platform.focus_element_by_id(&input_id);
577	                            no_cleanup()
578	                        })))
579	                    }
580	                    None => None,
581	                }
582	            }
583	
584	            Event::CompositionStart => {
585	                Some(TransitionPlan::context_only(|ctx| { ctx.is_composing = true; }))
586	            }
587	            Event::CompositionEnd => {
588	                Some(TransitionPlan::context_only(|ctx| { ctx.is_composing = false; }))
589	            }
590	
591	            _ => None,
592	        }
593	    }
