596	        state: &'a Self::State,
597	        ctx: &'a Self::Context,
598	        props: &'a Self::Props,
599	        send: &'a dyn Fn(Self::Event),
600	    ) -> Self::Api<'a> {
601	        Api { state, ctx, props, send }
602	    }
603	}
