    #[test]
    fn delete_trigger_has_localized_label() {
        let service = with_tags(&["apple"]);
        let api = service.connect(&|_| {});

        assert_eq!(
            api.tag_delete_trigger_attrs(0)
                .get(&HtmlAttr::Aria(AriaAttr::Label)),
